const {BigQuery} = require('@google-cloud/bigquery');

exports.processLargeData = async (event, context) => {
  const bigquery = new BigQuery();
  const datasetId = 'your_dataset_id';
  const tableId = 'your_table_id';

  try {
    // Set the max memory allocation to 8GB
    context.callbackWaitsForEmptyEventLoop = false;

    // Set the timeout to 540 seconds
    context.setTimeout(540000);

    const query = `
      SELECT *
      FROM \`your_project_id.${datasetId}.${tableId}\`
    `;

    const options = {
      location: 'US',
      useLegacySql: false,
    };

    const [job] = await bigquery.createQueryJob(query, options);
    console.log(`Job ${job.id} started`);

    // Wait for the job to complete
    const [rows] = await job.getQueryResults();

    // Process the rows here
    console.log('Data processed:', rows.length);

  } catch (error) {
    console.error('Error processing data:', error);
    throw new Error(error.message);
  }
};